def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45.0 + np.log1p(cap) * 30
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 120 * np.cbrt(cap) + 40 * np.cos(cap * 1.7) - 15 * np.sin(cap/3)
            else:
                base_priority -= 50 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.6) * 25 / i**1.1
            if cap % 2.5 < 0.3:
                base_priority += np.tan(cap / 10) * 30
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 3500 * delta ** 2 + 300 * (1 - np.sqrt(delta))
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.2)) * 20 / (j + 0.5)
            if int(cap * 4) % 5 == 0:
                base_priority += 60 * np.sin(cap / 10)
            if cap < 1.1:
                base_priority -= 15 * cap
        elif 3 < usage <= 4:
            base_priority += 2500 * (usage - 3)**1.5
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 12 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 15 / (k + 3)
                    if k == 11 and usage > 3.3:
                        fluctuation += 30
            if 0.1 < cap % 3 < 1.4:
                base_priority += 45 * np.cos(cap * 4)
        elif 2 < usage <= 3:
            base_priority += 1500 * (usage - 2) ** 2.7
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.55:
                    fluctuation += pwr * 20 / m
                    if m % 6 == 2:
                        fluctuation -= 5 * m
                else:
                    fluctuation += (1 - pwr) * 14 / (m + 4)
                    if m == 14 and usage > 2.6:
                        fluctuation += 25
            if cap % 2.7 < 0.7:
                base_priority += 40 * np.sin(cap * 2.7)
        elif 1 < usage <= 2:
            base_priority += 800 * (usage - 1) ** 3.5
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.65:
                    fluctuation += pwr * 28 / n
                    if n % 5 == 3:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 10 / (n + 2)
                    if n == 16 and usage > 1.8:
                        fluctuation += 18
            if cap % 1.4 < 0.25:
                base_priority += 32 * np.cos(cap * 2.3)
        elif 0.7 < usage <= 1:
            base_priority += 150 * (1 - usage)**1.1
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.35) * 15 / o
                if usage < 0.06 * o:
                    fluctuation -= 7 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 310
            elif cap < 0.75:
                base_priority += np.log1p(cap * 18) * 38
            else:
                base_priority += (cap % 7) * 26
        else:
            base_priority += 310 * (1 - usage)**2.8
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 16 / p
                if usage < 0.02 * p:
                    fluctuation -= 10 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 0.85:
                base_priority += np.log1p(cap * 28) * 50
            else:
                base_priority += (cap % 8) * 35
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 80
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for q in range(1, 9):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 0.85:
            priority += 45
            if usage > 0.88:
                priority += 70
            elif usage < 0.18:
                priority -= 35
            for r in range(1, 7):
                if int(cap * 1300) % (r + 5) == 0:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.11:
                priority -= 45
                for s in range(1, 9):
                    priority -= s * 6
            elif usage > 0.9:
                priority += 95
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 35
        affinity = 0
        if int(cap * 2600) % 17 == 0:
            affinity += 18
        if int(cap * 850) % 29 == 0:
            affinity -= 14
        if int(cap * 190) % 11 == 0:
            affinity += 16
        for u in range(1, 11):
            diff = abs(usage - u / 10)
            if diff < 0.015:
                affinity += 25 / u
            elif diff < 0.04:
                affinity += 12 / u
            else:
                affinity -= 6 / u
        for v in range(1, 9):
            mod_chk = int(cap * 1700) % (v + 8)
            if mod_chk == 0:
                affinity += v * 7
            elif mod_chk == 4:
                affinity -= v * 5
        for w in range(1, 6):
            mod_chk = int(usage * 1700) % (w + 7)
            if mod_chk == 0:
                affinity += 12 * w
            elif mod_chk == 4:
                affinity -= 9 * w
        priority += affinity
        if usage < 0.004:
            for x in range(1, 10):
                priority -= x * 12
        elif usage > 0.96:
            for y in range(1, 8):
                priority += y * 13
        if cap > 3.0:
            if cap % 1 < 0.05:
                priority += 45
            if (int(cap * 2700) % 19 == 0) and (usage > 0.75):
                priority += 70
            for z in range(1, 7):
                if (int(cap * 650) % (z + 10) == 3) and (usage < 0.88):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
